import { db } from '../config/firebase';
import { collection, getDocs } from "firebase/firestore";
import Fuse from 'fuse.js';

export async function citysuggester(city_name) {
  const citiesRef = collection(db, 'City');
  const querySnapshot = await getDocs(citiesRef);

  const options = {
    includeScore: true,
    threshold: 0.2,
    keys: ['cityName']
  }

  const fuse = new Fuse(querySnapshot.docs.map(doc => doc.data()), options);
  const result = fuse.search(city_name);

  return result.length > 0 ? result[0].item.cityName : null;
}
